using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference
            // c.Discriminator — keep the old name to avoid data incompatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "Product|123" to just "123".
            // Existing documents use the compound format — preserve it so that
            // FindAsync / point-reads continue to work against stored data.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex() — EF Core 9 Cosmos provider now throws at startup
        // for HasIndex calls. Cosmos DB indexing is managed via the container's
        // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

